    emit_u(0x42c80000u - 1u);        /* one ULP below 100.0 */
    emit_u(0x42c80000u);             /* 100.0 */
    emit_u(0x42c80000u + 1u);        /* one ULP above 100.0 */
    emit_u(0x3dcccccdu - 1u);        /* one ULP below nearest-float to 0.1 */
    emit_u(0x3dcccccdu);             /* nearest float to 0.1 */
    emit_u(0x3dcccccdu + 1u);        /* one ULP above nearest-float to 0.1 */
    emit_u(0x3c23d70au - 1u);        /* one ULP below nearest-float to 0.01 */
    emit_u(0x3c23d70au);             /* nearest float to 0.01 */
    emit_u(0x3c23d70au + 1u);        /* one ULP above nearest-float to 0.01 */
    emit_u(0x447a0000u - 1u);        /* one ULP below 1000.0 */
