/*
 * log10f() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly log10f  (test_log10f_opt.elf)
 *   2. Linked with toolchain's default log10f        (test_log10f_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc;

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;   /* prevent constant-folding of literal arguments */
    g_acc += log10f(vx);
#else
    float r = log10f(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);                      /* log10(+0) = -Inf */
    emit(-0.0f);                     /* log10(-0) = -Inf */
    emit_u(0x7fc00000u);             /* qNaN */
    emit_u(0x7f800001u);             /* sNaN */
    emit_u(0xffc00000u);             /* -qNaN */
    emit_u(0x7f800000u);             /* +Inf -> +Inf */
    emit_u(0xff800000u);             /* -Inf -> NaN (domain error) */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);             /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);             /* min negative subnormal -> NaN */
    emit_u(0x00400000u);             /* mid positive subnormal */
    emit_u(0x80400000u);             /* mid negative subnormal -> NaN */
    emit_u(0x007fffffu);             /* max subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);             /* max negative subnormal -> NaN */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(FLT_MIN);                   /* 2^-126, smallest normal: log10 very negative */
    emit(-FLT_MIN);                  /* negative -> NaN */
    emit_u(0x00800001u);             /* one ULP above FLT_MIN */
    emit(FLT_MAX);                   /* 0x7f7fffff: largest normal */
    emit(-FLT_MAX);                  /* negative -> NaN */
    emit_u(0x7f7ffffeu);             /* one ULP below FLT_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    /* log10(1.0) = 0 exactly; stresses polynomial near zero result */
    emit_u(0x3f7fffffu);             /* one ULP below 1.0 */
    emit(1.0f);                      /* log10(1.0) = 0.0 exactly */
    emit_u(0x3f800001u);             /* one ULP above 1.0 */
    emit_u(0x3f7ffff0u);             /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);             /* a few ULPs above 1.0 */
    emit(-1.0f);                     /* negative -> NaN */
    emit_u(0xbf7fffffu);             /* one ULP toward zero from -1.0 -> NaN */
    emit_u(0xbf800001u);             /* one ULP away from zero from -1.0 -> NaN */

    /* --- Section 5: Exponent switching points (6) --- */
    /* At power-of-2 boundaries the biased exponent increments */
    emit_u(0x3f000000u);             /* 0.5: log10(0.5) = -log10(2) */
    emit_u(0x3effffffu);             /* one ULP below 0.5 */
    emit_u(0x3f000001u);             /* one ULP above 0.5 */
    emit_u(0x40000000u);             /* 2.0: log10(2) = 0.30103... */
    emit_u(0x3fffffffu);             /* one ULP below 2.0 */
    emit_u(0x40000001u);             /* one ULP above 2.0 */

    /* --- Section 6: log10-specific mathematical constants (14) --- */
    /* Exact integer results: log10(10^n) = n */
    emit(10.0f);                     /* log10(10) = 1.0 exactly */
    emit(100.0f);                    /* log10(100) = 2.0 exactly */
    emit(1000.0f);                   /* log10(1000) = 3.0 exactly */
    emit(10000.0f);                  /* log10(10000) = 4.0 exactly */
    emit(0.1f);                      /* log10(0.1) = -1.0 exactly */
    emit(0.01f);                     /* log10(0.01) = -2.0 exactly */
    emit(0.001f);                    /* log10(0.001) = -3.0 exactly */
    /* Irrational log10 results */
    emit(2.0f);                      /* log10(2) = 0.30103... */
    emit(5.0f);                      /* log10(5) = 0.69897... */
    emit(0.5f);                      /* log10(0.5) = -0.30103... */
    emit(0.2f);                      /* log10(0.2) = -0.69897... */
    /* Mathematical constants as inputs */
    emit(2.71828182845904523536f);   /* e: log10(e) = 0.43429... */
    emit(0.43429448190325182765f);   /* log10(e) as input: log10(log10(e)) */
    emit(2.30258509299404568402f);   /* ln(10) as input: log10(ln(10)) */

    /* --- Section 7: Large, small, and domain-error inputs (8) --- */
    emit(1.0e10f);                   /* large positive */
    emit(1.0e20f);                   /* very large positive */
    emit(1.0e-10f);                  /* small positive */
    emit(1.0e-20f);                  /* very small positive */
    emit(1.0e-37f);                  /* near subnormal boundary */
    emit(-2.0f);                     /* negative -> NaN */
    emit(-0.5f);                     /* negative -> NaN */
    emit(-1.0e-10f);                 /* negative -> NaN */

    /* --- Section 8: ULP neighbors of key log10 transition points (15) --- */
    /* Near 10.0: log10(10.0) = 1.0 */
    emit_u(0x411fffffu);             /* one ULP below 10.0 */
    emit_u(0x41200000u);             /* 10.0 exactly */
    emit_u(0x41200001u);             /* one ULP above 10.0 */
    /* Near 100.0: log10(100.0) = 2.0 */
    emit_u(0x42c7ffffu);             /* one ULP below 100.0 */
    emit_u(0x42c80000u);             /* 100.0 exactly */
    emit_u(0x42c80001u);             /* one ULP above 100.0 */
    /* Near 0.1: log10(0.1) = -1.0; nearest float to 0.1 is 0x3dcccccd */
    emit_u(0x3dcccccc u);            /* one ULP below nearest-float to 0.1 */
    emit_u(0x3dcccccdu);             /* nearest float to 0.1 */
    emit_u(0x3dccccceu);             /* one ULP above nearest-float to 0.1 */
    /* Near 0.01: log10(0.01) = -2.0; nearest float to 0.01 is 0x3c23d70a */
    emit_u(0x3c23d709u);             /* one ULP below nearest-float to 0.01 */
    emit_u(0x3c23d70au);             /* nearest float to 0.01 */
    emit_u(0x3c23d70bu);             /* one ULP above nearest-float to 0.01 */
    /* Near 1000.0: log10(1000.0) = 3.0 */
    emit_u(0x447a0000u - 1u);        /* one ULP below 1000.0 */
    emit_u(0x447a0000u);             /* 1000.0 exactly */
    emit_u(0x447a0000u + 1u);        /* one ULP above 1000.0 */

    /* --- Section 9: Powers-of-2 across the normal range (8) --- */
    emit_u(0x01000000u);             /* 2^-125 */
    emit_u(0x02000000u);             /* 2^-123 */
    emit_u(0x04000000u);             /* 2^-121 */
    emit_u(0x08000000u);             /* 2^-119 */
    emit_u(0x10000000u);             /* 2^-115 */
    emit_u(0x20000000u);             /* 2^-95 */
    emit_u(0x30000000u);             /* 2^-63 */
    emit_u(0x5e000000u);             /* 2^60 */

    /* --- Section 10: Hard cases and polynomial branch points (22) --- */
    /* sqrt(10) ~ 3.16228: log10(sqrt(10)) = 0.5 exactly */
    emit_u(0x404f3344u);             /* nearest float to sqrt(10) */
    emit_u(0x404f3343u);             /* one ULP below sqrt(10) */
    emit_u(0x404f3345u);             /* one ULP above sqrt(10) */
    /* 10^0.25 ~ 1.77828: log10(10^0.25) = 0.25 */
    emit_u(0x3fe36573u);             /* nearest float to 10^0.25 */
    /* 10^0.75 ~ 5.62341: log10(10^0.75) = 0.75 */
    emit_u(0x40b3b5a0u);             /* nearest float to 10^0.75 */
    /* Integer values 3-9: all irrational log10 results */
    emit(3.0f);                      /* log10(3) = 0.47712... */
    emit(4.0f);                      /* log10(4) = 0.60206... */
    emit(6.0f);                      /* log10(6) = 0.77815... */
    emit(7.0f);                      /* log10(7) = 0.84510... */
    emit(8.0f);                      /* log10(8) = 0.90309... */
    emit(9.0f);                      /* log10(9) = 0.95424... */
    /* Values spanning decades */
    emit(1.5f);                      /* log10(1.5) = 0.17609... */
    emit(20.0f);                     /* log10(20) = 1.30103... */
    emit(50.0f);                     /* log10(50) = 1.69897... */
    emit(200.0f);                    /* log10(200) = 2.30103... */
    emit(500.0f);                    /* log10(500) = 2.69897... */
    emit_u(0x42800000u);             /* 64.0: log10(64) = 1.80618... */
    /* One more domain error and FLT_MAX neighbor */
    emit(-100.0f);                   /* negative -> NaN */
    emit_u(0x7f7fffffu);             /* FLT_MAX = 0x7f7fffff */
}

